import React, { useEffect, useState } from "react";
import API from "../services/api";

function TaskList() {

  const [tasks, setTasks] = useState([]);

  useEffect(() => {
    API.get("tasks/")
      .then((res) => setTasks(res.data));
  }, []);

  return (
    <div>
      <h2>Tasks</h2>

      {tasks.map((task) => (
        <div key={task.id}>
          <h4>{task.title}</h4>
          <p>{task.description}</p>
        </div>
      ))}
    </div>
  );
}

export default TaskList;
